// // This is a 2-bit priority encoder that decodes the highest set bit of the input d[3:0] and sets y[1:0] accordingly. If no bits are set, y[1:0] is set to 00 and valid is set to 0.
module top_module (
    input [3:0] d,
    output reg [1:0] y,
    output reg valid
);

    always @(*) begin
        valid = 1;
        casex (d)
            4'b1xxx: y = 2'b11;
            4'b01xx: y = 2'b10;
            4'b001x: y = 2'b01;
            4'b0001: y = 2'b00;
            default: begin
                y = 2'b00;
                valid = 0;
            end
        endcase
    end

endmodule
